# SYMPTOM: KL loss converges to ~0, reconstruction loss dominates.
# The encoder outputs near-prior (mu≈0, log_var≈0) for all inputs;
# the decoder ignores z and acts as an unconditional model.

# DIAGNOSIS:
# kl_loss ≈ 0 means: encoder learns to output the prior for all inputs.
# reconstruction_loss still decreasing: decoder is powerful enough to reconstruct without z.

# MITIGATION 1: KL annealing — ramp beta from 0 to 1 over first N epochs
def beta_schedule(epoch, anneal_epochs=50):
    return min(1.0, epoch / anneal_epochs)

# MITIGATION 2: Free bits — do not penalise KL below a minimum threshold per dimension
def free_bits_kl(mu, log_var, free_bits=0.25):
    kl_per_dim = -0.5 * (1 + log_var - mu.pow(2) - log_var.exp())
    # Clamp: do not penalise dimensions that are already compressed
    kl_per_dim = kl_per_dim.clamp(min=free_bits)
    return kl_per_dim.mean()

